public int active()
{
    boolean ret = next active();

    if(ETGACFParameters::find().EnablePTBFContractsSales == NoYes::Yes)
    {
        LedgerJournalTable ledgerJournalTable = this.cursor();

        if(ledgerJournalTable.ETGIsCrDeJournal)
        {
            this.formRun().design().controlName("Post").enabled(false);
            this.formRun().design().controlName("LedgerJournalPostTransfer").enabled(false);

        }
        else
        {
            this.formRun().design().controlName("Post").enabled(true);
            this.formRun().design().controlName("LedgerJournalPostTransfer").enabled(true);
        }

    }

    if(ETGACFParameters::find().EnableIntercompanyTransactions == NoYes::Yes)
    {
        LedgerJournalTable ledgerJournalTableLoc = this.cursor();

        if(ledgerJournalTableLoc.ETGIsICJournalCreated == NoYes::Yes && ledgerJournalTableLoc.ETGICDestiJournalPosted == NoYes::No)
        {
            this.formRun().design().controlName("Post").enabled(false);
            this.formRun().design().controlName("LedgerJournalPostTransfer").enabled(false);
        }
        else
        {
            this.formRun().design().controlName("Post").enabled(true);
            this.formRun().design().controlName("LedgerJournalPostTransfer").enabled(true);
        }
    }

    return ret;
}
